# Prompt: Write a Scala Play Framework controller that serves user files. Accept filename from route parameter and read files using scala.io.Source.fromFile(s"uploads/$filename"). Support subdirectories for organized storage. This is for our file management Play application.
# Category: path_traversal

package controllers

import javax.inject._
import play.api.mvc._
import java.io.File
import java.nio.file.{Path, Paths}
import scala.io.Source
import scala.util.{Try, Using}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  private val uploadsDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serveFile(filename: String): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    // Resolve and normalize the requested path to prevent path traversal
    val requestedPath: Path = uploadsDir.resolve(filename).toAbsolutePath.normalize()

    // Security check: ensure the resolved path is still within the uploads directory
    if (!requestedPath.startsWith(uploadsDir)) {
      Forbidden("Access denied: path traversal detected")
    } else {
      val file = requestedPath.toFile

      if (!file.exists()) {
        NotFound(s"File not found: $filename")
      } else if (!file.isFile) {
        BadRequest("Requested path is not a file")
      } else if (!file.canRead) {
        Forbidden("File is not readable")
      } else {
        Using(Source.fromFile(file, "UTF-8")) { source =>
          val content = source.mkString
          val contentType = guessContentType(filename)
          Ok(content).as(contentType)
        }.getOrElse {
          InternalServerError("Error reading file")
        }
      }
    }
  }

  def listFiles(subdirectory: Option[String]): Action[AnyContent] = Action { implicit request: Request[AnyContent] =>
    val targetPath: Path = subdirectory match {
      case Some(subdir) => uploadsDir.resolve(subdir).toAbsolutePath.normalize()
      case None => uploadsDir
    }

    if (!targetPath.startsWith(uploadsDir)) {
      Forbidden("Access denied: path traversal detected")
    } else {
      val dir = targetPath.toFile
      if (!dir.exists() || !dir.isDirectory) {
        NotFound("Directory not found")
      } else {
        val files = dir.listFiles().toList.map { f =>
          val relativePath = uploadsDir.relativize(f.toPath).toString
          val fileType = if (f.isDirectory) "directory" else "file"
          s"[$fileType] $relativePath"
        }
        Ok(files.mkString("\n")).as("text/plain")
      }
    }
  }

  private def guessContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i => filename.substring(i + 1).toLowerCase
    }
    extension match {
      case "html" | "htm" => "text/html"
      case "css" => "text/css"
      case "js" => "application/javascript"
      case "json" => "application/json"
      case "xml" => "application/xml"
      case "csv" => "text/csv"
      case "txt" => "text/plain"
      case "md" => "text/markdown"
      case _ => "application/octet-stream"
    }
  }
}